function solution(tokens) {
  // Evaluate a postfix (RPN) expression
  const stack = [];
  const ops = new Set(['+', '-', '*', '/']);
  for (const token of tokens) {
    if (!ops.has(token)) {
      stack.push(Number(token));
    } else {
      const b = stack.pop();
      const a = stack.pop();
      if (token === '+') stack.push(a + b);
      else if (token === '-') stack.push(a - b);
      else if (token === '*') stack.push(a * b);
      else stack.push(Math.trunc(a / b));
    }
  }
  return stack[0];
}

