function solution(head) {
  // Detect a cycle in a linked list using Floyd's two-pointer algorithm
  // head is a node object with a .next property
  let slow = head, fast = head;
  while (fast !== null && fast.next !== null) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) return true;
  }
  return false;
}

