// Serialize and deserialize a binary tree using BFS level-order encoding
const solution = {
  serialize(root) {
    if (!root) return '[]';
    const queue = [root], res = [];
    while (queue.length) {
      const node = queue.shift();
      if (node) {
        res.push(node.val);
        queue.push(node.left, node.right);
      } else res.push('null');
    }
    while (res[res.length-1] === 'null') res.pop();
    return '[' + res.join(',') + ']';
  },
  deserialize(data) {
    const vals = data.slice(1,-1).split(',');
    if (!vals[0] || vals[0]==='null') return null;
    const root = {val: parseInt(vals[0]), left:null, right:null};
    const queue = [root];
    let i = 1;
    while (queue.length && i < vals.length) {
      const node = queue.shift();
      if (i < vals.length && vals[i] !== 'null') {
        node.left = {val:parseInt(vals[i]),left:null,right:null};
        queue.push(node.left);
      }
      i++;
      if (i < vals.length && vals[i] !== 'null') {
        node.right = {val:parseInt(vals[i]),left:null,right:null};
        queue.push(node.right);
      }
      i++;
    }
    return root;
  }
};

