    groups = defaultdict(list)
    for word in words:
        key = ''.join(sorted(word))
        groups[key].append(word)
    # Return groups in order of first appearance
    seen = {}
    order = []
    for word in words:
        key = ''.join(sorted(word))
        if key not in seen:
            seen[key] = True
            order.append(groups[key])
    return order

