function parseCsvLine(line, delimiter = ',') {
  if (typeof line !== 'string') throw new TypeError('line must be a string');
  const fields = [];
  let i = 0;
  while (i <= line.length) {
    if (i === line.length) { fields.push(''); break; }
    if (line[i] === '"') {
      // quoted field
      let field = '';
      i++;
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i+1] === '"') { field += '"'; i += 2; }
          else { i++; break; }
        } else {
          field += line[i++];
        }
      }
      fields.push(field);
      // expect delimiter or end
      if (i < line.length && line[i] === delimiter) i++;
      else if (i < line.length) throw new Error('Malformed CSV: unexpected char after quoted field');
    } else {
      let field = '';
      while (i < line.length && line[i] !== delimiter) field += line[i++];
      fields.push(field);
      if (i < line.length) i++; // skip delimiter
      else break;
    }
  }
  // Handle empty line
  if (line === '') return [''];
  return fields;
}

// Tests
