function lruCache(capacity) {
  const map = new Map();
  return {
    get(key) {
      if (!map.has(key)) return -1;
      const val = map.get(key);
      map.delete(key); map.set(key, val); // move to end
      return val;
    },
    put(key, value) {
      if (map.has(key)) map.delete(key);
      else if (map.size >= capacity) map.delete(map.keys().next().value); // evict LRU
      map.set(key, value);
    }
  };
}

const assert = require('assert');
const c = lruCache(2);
c.put(1, 1); c.put(2, 2);
assert.strictEqual(c.get(1), 1); // cache hit
c.put(3, 3); // evicts 2
assert.strictEqual(c.get(2), -1); // evicted
assert.strictEqual(c.get(3), 3);
c.put(4, 4); // evicts 1 (LRU was 1 after get(1), then 3 was used)
assert.strictEqual(c.get(1), -1); // evicted
assert.strictEqual(c.get(3), 3);
assert.strictEqual(c.get(4), 4);
// Capacity 1
const c2 = lruCache(1);
c2.put(1, 10); assert.strictEqual(c2.get(1), 10);
c2.put(2, 20); assert.strictEqual(c2.get(1), -1); assert.strictEqual(c2.get(2), 20);
