function minWindowSubstring(text, pattern) {
  if (!text || !pattern) return '';
  const need = {};
  for (const c of pattern) need[c] = (need[c] || 0) + 1;
  let have = 0, required = Object.keys(need).length;
  const window = {};
  let best = '', lo = 0;
  for (let hi = 0; hi < text.length; hi++) {
    const c = text[hi];
    window[c] = (window[c] || 0) + 1;
    if (need[c] && window[c] === need[c]) have++;
    while (have === required) {
      const sub = text.slice(lo, hi + 1);
      if (!best || sub.length < best.length) best = sub;
      const lc = text[lo];
      window[lc]--;
      if (need[lc] && window[lc] < need[lc]) have--;
      lo++;
    }
  }
  return best;
}

