  }
  return false;
}
```

After (simplified):
```javascript
function canAccessFeature(user) {
  if (user.isActive && user.hasSubscription) {
    if (!user.isAdmin) {
      return !user.trialExpired;
    }
    return true;
  }
  return false;
}
```

Or more concisely as a single expression:
```javascript
function canAccessFeature(user) {
