                    errors.append(f'{path}:{lineno}: expected 4 fields, got {len(parts)}')
                    continue
                ts_raw, service, status_code_raw, latency_raw = parts

                # Validate timestamp
                try:
                    ts = parse_iso8601(ts_raw.strip())
                except ValueError as e:
                    errors.append(f'{path}:{lineno}: {e}')
                    continue

                try:
                    status_code = int(status_code_raw.strip())
                    latency_ms = int(latency_raw.strip())
                except ValueError:
                    errors.append(f'{path}:{lineno}: non-integer status_code or latency_ms')
                    continue

                if status_code >= 500:
                    records.append({
                        'timestamp': ts_raw.strip(),
                        'service': service.strip(),
                        'status_code': status_code,
                        'latency_ms': latency_ms,
                    })

    if errors:
        raise ValueError('Parse errors:\n' + '\n'.join(errors))

    df = pd.DataFrame(records)
    df.to_parquet('failed_requests.parquet', index=False)
    print(f'Wrote {len(records)} failed records to failed_requests.parquet')

run()
```

Key steps: (1) glob all *.log files; (2) split each line on |; (3) validate ISO 8601 timestamp by trying multiple formats; (4) filter status_code >= 500; (5) accumulate errors without stopping early; (6) build DataFrame and write Parquet via pandas/pyarrow.

