The template method pattern defines the skeleton of an algorithm in a base class, deferring certain steps to subclasses. The base class calls abstract methods at specific points; subclasses provide concrete implementations without changing the overall algorithm structure. This avoids code duplication while allowing variation in specific steps.

```csharp
using System;

// Abstract class with template method
abstract class DataParser {
    // Template method - defines the algorithm skeleton
    public void ParseFile(string data) {
        Console.WriteLine($"--- Starting {GetFormatName()} parsing ---");
        string[] lines = ReadLines(data);
        var records = ProcessLines(lines);
        PrintResults(records);
    }

    protected abstract string GetFormatName();
    protected abstract string[] ReadLines(string data);
    protected abstract string[] ProcessLines(string[] lines);

    // Hook with default behavior
    protected virtual void PrintResults(string[] records) {
        Console.WriteLine($"Parsed {records.Length} record(s):");
        foreach (var r in records) Console.WriteLine("  " + r);
    }
}

// CSV subclass
class CsvParser : DataParser {
    protected override string GetFormatName() => "CSV";
    protected override string[] ReadLines(string data) => data.Split('\n');
    protected override string[] ProcessLines(string[] lines) {
        return Array.ConvertAll(lines, l => string.Join(" | ", l.Split(',')));
    }
}

// JSON subclass (simplified)
class JsonParser : DataParser {
    protected override string GetFormatName() => "JSON";
    protected override string[] ReadLines(string data) =>
        data.Trim('{', '}').Split(',');
    protected override string[] ProcessLines(string[] lines) {
        return Array.ConvertAll(lines, l => l.Trim().Replace('"', ' ').Trim());
    }
}

class TemplateMethodDemo {
    static void Main() {
        new CsvParser().ParseFile("Alice,30,Engineer\nBob,25,Designer");
        new JsonParser().ParseFile("{\"name\":\"Carol\",\"age\":28}");
    }
}
```

