Three distinct states for a query parameter: missing (key absent), empty (key present, value is empty string), explicit null or zero. These must not be conflated:

```ts
type ParamState = { present: false } | { present: true; value: string };

function getParam(url: URL, key: string): ParamState {
  if (!url.searchParams.has(key)) return { present: false };
  return { present: true, value: url.searchParams.get(key) ?? '' };
}

