Parse deeply nested parentheses without recursion by using an explicit stack:

```python
def parse_expr(expr: str):
    """Returns AST or value. Uses iterative approach to avoid stack overflow."""
    # Tokenize
    tokens = tokenize(expr)  # produces NUMBER, PLUS, MINUS, LPAREN, RPAREN tokens
    # Operator-precedence parsing using two stacks (shunting-yard)
    output = []   # operand stack
    ops = []      # operator stack
    PREC = {'+': 1, '-': 1, '*': 2, '/': 2}

    for tok in tokens:
        if tok.type == 'NUMBER':
            output.append(float(tok.value))
        elif tok.type == 'OP':
            while ops and ops[-1] != '(' and PREC.get(ops[-1], 0) >= PREC[tok.value]:
                apply_op(output, ops.pop())
            ops.append(tok.value)
        elif tok.type == 'LPAREN':
            ops.append('(')
        elif tok.type == 'RPAREN':
            while ops and ops[-1] != '(':
                apply_op(output, ops.pop())
            if not ops:
                raise ValueError('Mismatched parentheses')
            ops.pop()  # remove '('
    while ops:
        if ops[-1] == '(':
            raise ValueError('Mismatched parentheses')
        apply_op(output, ops.pop())
    return output[0] if output else None

def apply_op(output, op):
    b, a = output.pop(), output.pop()
    output.append({'+':a+b,'-':a-b,'*':a*b,'/':a/b}[op])
```
The shunting-yard algorithm is iterative and handles depth 50,000 without recursion.

