    dir := filepath.Dir(path)
    if err := os.MkdirAll(dir, 0755); err != nil {
        return nil, fmt.Errorf("creating log directory %s: %w", dir, err)
    }
    f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
    if err != nil {
        return nil, fmt.Errorf("opening log file %s: %w", path, err)
    }
    return f, nil
}

MkdirAll creates the full directory tree if missing (no-op if it already exists). O_APPEND|O_CREATE|O_WRONLY opens for appending, creating the file if it doesn't exist. Errors include the path for debuggability.

