function getNestedProperty(obj, path) {
  if (obj === null || obj === undefined) return undefined;
  const parts = Array.isArray(path) ? path : path.split('.');
  let cur = obj;
  for (const part of parts) {
    if (cur === null || cur === undefined) return undefined;
    cur = cur[part];
  }
  return cur;
}

// Usage: getNestedProperty(user, 'address.city.name')

Returns undefined (never throws) if any intermediate property is null, undefined, or simply absent. Handles arrays in the path (e.g. 'items.0.name'). Does not use eval. This is equivalent to optional chaining (obj?.address?.city?.name) but works for dynamic paths computed at runtime.

