def parse_uploaded_json(file_bytes: bytes) -> dict | list | None:
    # Try UTF-8 first
    for encoding in ('utf-8-sig', 'utf-8', 'utf-16', 'latin-1'):
        try:
            text = file_bytes.decode(encoding)
            break
        except (UnicodeDecodeError, ValueError):
            continue
    else:
        print('Could not decode file bytes with any known encoding')
        return None
    try:
        return json.loads(text)
    except json.JSONDecodeError as e:
        print(f'Invalid JSON: {e}')
        return None

Tries multiple encodings in order of likelihood. 'utf-8-sig' handles BOM-prefixed UTF-8. Falls back to latin-1 as a last resort (never raises UnicodeDecodeError). Returns None on both decode and parse failure.

