#include <stdio.h>
#include <string.h>

int read_first_line(const char *path, char *buf, size_t bufsize) {
    if (!path || !buf || bufsize == 0) return -1;
    FILE *f = fopen(path, "r");
    if (!f) {
        perror(path);
        buf[0] = '\0';
        return -1;
    }
    if (!fgets(buf, (int)bufsize, f)) {
        buf[0] = '\0';
        fclose(f);
        return 0; // empty file is not an error
    }
    // strip trailing newline
    buf[strcspn(buf, "\n")] = '\0';
    fclose(f);
    return 0;
}

Returns -1 on error with errno set via perror. Sets buf to empty string on failure so callers always have a valid (if empty) string. bufsize prevents buffer overflow. fclose is always called.

