func readFile(at path: String) -> String? {
    let url = URL(fileURLWithPath: path)
    guard url.isFileURL else { return nil }
    do {
        return try String(contentsOf: url, encoding: .utf8)
    } catch CocoaError.fileNoSuchFile, CocoaError.fileReadNoSuchFile {
        return nil // file not found
    } catch {
        print("Error reading file at \(path): \(error)")
        return nil
    }
}

Returns nil for missing file and for any other error (permissions, encoding). Uses typed catch for the not-found case to distinguish it. URL(fileURLWithPath:) handles path validation; the isFileURL guard catches non-file paths. String(contentsOf:encoding:) throws on encoding mismatch.

