import time

def retry_on_timeout(fn, max_attempts=4, delay=1.0):
    last_err = None
    for attempt in range(max_attempts):
        try:
            return fn()
        except TimeoutError as e:
            last_err = e
            if attempt < max_attempts - 1:
                print(f'Attempt {attempt+1} timed out, retrying in {delay}s...')
                time.sleep(delay)
    raise last_err

Retries up to max_attempts times. Only catches TimeoutError — other exceptions propagate immediately (fail fast). Sleeps between retries to avoid hammering the resource. Re-raises the last TimeoutError if all attempts fail. For exponential backoff: delay *= 2 after each attempt.

