interface CsvRow { name: string; age: number; city: string; }

function parseCsvLine(line: string): CsvRow | null {
  if (!line || line.trim() === '') return null;
  const parts = line.split(',');
  if (parts.length < 3) {
    console.warn(`CSV line has fewer than 3 fields: ${line}`);
    return null;
  }
  const [name, ageStr, ...cityParts] = parts;
  const age = parseInt(ageStr.trim(), 10);
  if (isNaN(age)) {
    console.warn(`Invalid age value: ${ageStr}`);
    return null;
  }
  const city = cityParts.join(',').trim(); // handle city names with commas
  return { name: name.trim(), age, city };
}

Returns null on invalid input. Handles city names containing commas by joining remaining parts.

