import json, os
from pathlib import Path

def merge_json_files(paths: list[str]) -> list[dict]:
    merged = []
    for path in paths:
        try:
            text = Path(path).read_text(encoding='utf-8')
            data = json.loads(text)
            if not isinstance(data, list):
                print(f'Skipping {path}: top-level value is not an array')
                continue
            merged.extend(data)
        except FileNotFoundError:
            print(f'File not found, skipping: {path}')
        except json.JSONDecodeError as e:
            print(f'Invalid JSON in {path}: {e}')
    return merged

Skips files that are missing or have invalid JSON rather than aborting the entire merge. Also validates that each file's top-level value is an array.

