type Message struct { ID string `json:"id"`; Text string `json:"text"` }

func DecodeMessage(data []byte) (*Message, error) {
    if len(data) == 0 {
        return nil, nil // empty input: no message, no error
    }
    var msg Message
    if err := json.Unmarshal(data, &msg); err != nil {
        return nil, fmt.Errorf("decoding message: %w", err)
    }
    return &msg, nil
}

Returns (nil, nil) for empty input as a sentinel meaning 'no message'. Returns (*Message, nil) on success. Returns (nil, error) on parse failure. Callers check the pointer for nil before using the message. Uses json.Unmarshal rather than a Decoder to work on a byte slice directly.

868.answer:
async function fetchWithRetry(url, maxRetries = 3, baseDelay = 1000) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url);
      if (res.status === 503) {
        if (attempt === maxRetries) throw new Error(`503 after ${maxRetries} retries`);
        const delay = baseDelay * Math.pow(2, attempt);
        console.warn(`503 on attempt ${attempt + 1}, retrying in ${delay}ms`);
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
      return await res.json();
    } catch (err) {
      if (attempt === maxRetries) throw err;
    }
  }
}

Uses exponential backoff (1s, 2s, 4s). Only retries 503 (service unavailable); other errors propagate. Throws after exhausting retries.

