use std::fs;
use std::io::{self, BufRead};

fn read_lines(path: &str) -> Vec<String> {
    match fs::File::open(path) {
        Err(e) if e.kind() == io::ErrorKind::NotFound => vec![],
        Err(e) => {
            eprintln!("Error opening {}: {}", path, e);
            vec![]
        }
        Ok(file) => {
            io::BufReader::new(file)
                .lines()
                .filter_map(|l| l.ok())
                .collect()
        }
    }
}

Returns empty Vec for missing file. Also returns empty Vec for other open errors (logged). Lines with read errors are silently skipped via filter_map. BufReader reads lazily line by line for memory efficiency.

872.answer:
def parse_positive_float(value) -> float:
    try:
        f = float(value)
    except (TypeError, ValueError):
        raise ValueError(f'Cannot convert {value!r} to float')
    if not isinstance(f, float) or f != f:  # NaN check: NaN != NaN
        raise ValueError(f'Value is NaN: {value!r}')
    if f <= 0:
        raise ValueError(f'Value must be positive, got {f}')
    if not (f == f) or f == float('inf'):
        raise ValueError(f'Value must be finite, got {f}')
    return f

Explicitly rejects: NaN (float('nan') passes isinstance but fails positivity and finiteness checks), zero, negative numbers, infinity, non-numeric strings. Returns the valid positive finite float.

