function normalizeStringArray(input) {
  if (input === null || input === undefined) return [];
  if (!Array.isArray(input)) return [];
  return input
    .filter(item => item !== null && item !== undefined)
    .map(item => String(item)); // coerce non-strings to string
}

Returns [] for null, undefined, or non-array input. Filters out null/undefined elements. Coerces other element types (numbers, booleans) to strings rather than throwing — document this behavior if strict string-only is needed. For strict mode: .filter(item => typeof item === 'string') and throw on any non-string element.

