func ParseBoolParam(r *http.Request, key string) (bool, bool) {
    // Returns (value, found)
    vals, ok := r.URL.Query()[key]
    if !ok || len(vals) == 0 {
        return false, false // key absent
    }
    s := strings.TrimSpace(vals[0])
    switch strings.ToLower(s) {
    case "true", "1", "yes":
        return true, true
    case "false", "0", "no", "":
        return false, true
    default:
        return false, false // present but unrecognizable
    }
}

Returns (value, found) tuple. Key absent → (false, false). Key present but unrecognizable → (false, false). Empty string value → (false, true) meaning explicitly set to false. Handles common bool string variants.

