import yaml
from pathlib import Path

def load_yaml_config(path: str) -> dict | None:
    try:
        text = Path(path).read_text(encoding='utf-8')
    except FileNotFoundError:
        return None
    try:
        data = yaml.safe_load(text)
        if data is None:
            return {}  # empty YAML file is valid, return empty dict
        return data
    except yaml.YAMLError as e:
        raise ValueError(f'Invalid YAML in {path}: {e}') from e

Returns None for missing file (caller can use default config). Returns empty dict for empty/null YAML. Raises ValueError for malformed YAML so the caller knows the file exists but is broken. Uses safe_load to prevent arbitrary Python object deserialization.

