async function callApiWithAuth(url, token) {
  try {
    const res = await fetch(url, {
      headers: { Authorization: `Bearer ${token}` }
    });
    if (res.status === 401) {
      console.warn('Authentication failed (401). Token may be expired.');
      return null;
    }
    if (!res.ok) {
      throw new Error(`API error ${res.status}: ${await res.text()}`);
    }
    return await res.json();
  } catch (err) {
    if (err.message?.startsWith('API error')) throw err; // re-throw non-auth errors
    console.error('Network error:', err);
    return null;
  }
}

Returns null specifically for 401 (caller can refresh token). Re-throws other HTTP errors. Returns null for network errors.
